/**
 * Adaptation of {@code NodeWrappersTestsContributor} tp JUnit5 API.
 */
public class JUnit5InprocessTestsContributor extends AbstractInProcessTestContributor implements JUnit5TestContributor {

  public JUnit5InprocessTestsContributor(MPSProject mpsProject, String runConfigurationName, Iterable<? extends ITestNodeWrapper> testNodes) {
    super(mpsProject, runConfigurationName, testNodes);
  }

  @Override
  public List<DiscoverySelector> collectSelectors() {
    return new ModelAccessHelper(myProject.getModelAccess()).runReadAction(() -> {
      final List<DiscoverySelector> selectorsList = new ArrayList<DiscoverySelector>();
      InProcessExecutionFilter filter = new InProcessExecutionFilter();
      for (ITestNodeWrapper testNode : myTestNodes) {
        String fqName = testNode.getFqName();
        final SModule testModule = testNode.getTestNodeModule().resolve(myProject.getRepository());
        SNode testNodeSrc = testNode.getNodePointer().resolve(myProject.getRepository());
        SModel testModel = (testNodeSrc == null ? null : testNodeSrc.getModel());
        if (testNode.isTestCase()) {
          selectorsList.add(processTestCase(filter, testNode, testModule, testModel, fqName));
        } else {
          selectorsList.add(processTestMethod(filter, testNode, testModule, testModel, fqName));
        }
      }
      return selectorsList;
    });
  }

  @NotNull
  private DiscoverySelector processTestCase(InProcessExecutionFilter filter, ITestNodeWrapper testNode, SModule testModule, SModel testModel, String fqName) {
    try {
      filter.check(testNode, testModel);
      return selectorForTestClass(fqName, testModule);
    } catch (InProcessExecutionFilter.InProcessCheckException e) {
      notifyByBaloonCheckException(e, testNode);
      return createFailedSelectorForClass(fqName, e);
    } catch (ClassNotFoundException e) {
      notifyByBaloonCLNF(e, testNode);
      return createFailedSelectorForClass(fqName, e);
    } catch (Exception e) {
      return createFailedSelectorForClass(fqName, e);
    }
  }

  @NotNull
  private DiscoverySelector processTestMethod(InProcessExecutionFilter filter, ITestNodeWrapper testNode, SModule testModule, SModel testModel, String fqName) {
    int index = fqName.lastIndexOf('.');
    String testFqName = fqName.substring(0, index);
    String methodName = fqName.substring(index + 1);
    try {
      filter.check(testNode, testModel);
      return selectorForTestMethod(testFqName, methodName, testModule);

    } catch (InProcessExecutionFilter.InProcessCheckException e) {
      notifyByBaloonCheckException(e, testNode);
      return createFailedSelectorForMethod(testFqName, methodName, e);
    } catch (ClassNotFoundException e) {
      notifyByBaloonCLNF(e, testNode);
      return createFailedSelectorForMethod(testFqName, methodName, e);
    } catch (Exception e) {
      return createFailedSelectorForMethod(testFqName, methodName, e);
    }
  }

  private DiscoverySelector createFailedSelectorForClass(String fqName, Exception e) {
    // FIXME implement using special TestEngine
    throw new UnsupportedOperationException("not implemented");
  }

  private DiscoverySelector createFailedSelectorForMethod(String testFqName, String methodName, Exception e) {
    // FIXME implement using special TestEngine
    throw new UnsupportedOperationException("not implemented");
  }

  private DiscoverySelector selectorForTestMethod(String fqName, String methodName, SModule module) throws ClassNotFoundException, ModuleClassLoaderIsNullException {
    final Class<?> aClass = loadTestClass(fqName, module);
    return DiscoverySelectors.selectMethod(aClass, methodName);
  }

  private DiscoverySelector selectorForTestClass(String fqName, SModule module) throws ClassNotFoundException, ModuleClassLoaderIsNullException {
    final Class<?> aClass = loadTestClass(fqName, module);
    return DiscoverySelectors.selectClass(aClass);
  }


}
